import{_ as a,o as e,c as n,ae as p}from"./chunks/framework.C7FLYIpo.js";const u=JSON.parse('{"title":"OpenProse","description":"OpenProse: OpenClaw의 .prose 워크플로, 슬래시 명령어, 상태","frontmatter":{"title":"OpenProse","description":"OpenProse: OpenClaw의 .prose 워크플로, 슬래시 명령어, 상태"},"headers":[],"relativePath":"prose.md","filePath":"prose.md","lastUpdated":null}'),o={name:"prose.md"};function l(t,s,i,r,c,d){return e(),n("div",null,[...s[0]||(s[0]=[p(`<h1 id="openprose" tabindex="-1">OpenProse <a class="header-anchor" href="#openprose" aria-label="Permalink to &quot;OpenProse&quot;">​</a></h1><p>OpenProse는 AI 세션 오케스트레이션을 위한 이식 가능한 마크다운 우선 워크플로 형식입니다. OpenClaw에서는 OpenProse 스킬 팩과 <code>/prose</code> 슬래시 명령어를 설치하는 플러그인으로 제공됩니다. 프로그램은 <code>.prose</code> 파일에 존재하며 명시적 제어 플로로 여러 서브에이전트를 생성할 수 있습니다.</p><p>공식 사이트: <a href="https://www.prose.md" target="_blank" rel="noreferrer">https://www.prose.md</a></p><h2 id="무엇을-할-수-있습니까" tabindex="-1">무엇을 할 수 있습니까 <a class="header-anchor" href="#무엇을-할-수-있습니까" aria-label="Permalink to &quot;무엇을 할 수 있습니까&quot;">​</a></h2><ul><li>명시적 병렬성을 갖춘 멀티에이전트 리서치 + 합성.</li><li>반복 가능한 승인 안전 워크플로 (코드 리뷰, 인시던트 분류, 콘텐츠 파이프라인).</li><li>지원되는 에이전트 런타임에서 실행할 수 있는 재사용 가능한 <code>.prose</code> 프로그램.</li></ul><h2 id="설치-활성화" tabindex="-1">설치 + 활성화 <a class="header-anchor" href="#설치-활성화" aria-label="Permalink to &quot;설치 + 활성화&quot;">​</a></h2><p>번들 플러그인은 기본적으로 비활성화됩니다. OpenProse를 활성화하십시오:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> plugins</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> open-prose</span></span></code></pre></div><p>플러그인 활성화 후 게이트웨이를 재시작하십시오.</p><p>개발/로컬 체크아웃: <code>openclaw plugins install ./path/to/local/open-prose-plugin</code></p><p>관련 문서: <a href="/openclaw-docs-ko/tools/plugin">플러그인</a>, <a href="/openclaw-docs-ko/plugins/manifest">플러그인 매니페스트</a>, <a href="/openclaw-docs-ko/tools/skills">스킬</a>.</p><h2 id="슬래시-명령어" tabindex="-1">슬래시 명령어 <a class="header-anchor" href="#슬래시-명령어" aria-label="Permalink to &quot;슬래시 명령어&quot;">​</a></h2><p>OpenProse는 <code>/prose</code>를 사용자 호출 가능한 스킬 명령어로 등록합니다. OpenProse VM 지침으로 라우팅되며 내부적으로 OpenClaw 도구를 사용합니다.</p><p>일반 명령어:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/prose help</span></span>
<span class="line"><span>/prose run &lt;file.prose&gt;</span></span>
<span class="line"><span>/prose run &lt;handle/slug&gt;</span></span>
<span class="line"><span>/prose run &lt;https://example.com/file.prose&gt;</span></span>
<span class="line"><span>/prose compile &lt;file.prose&gt;</span></span>
<span class="line"><span>/prose examples</span></span>
<span class="line"><span>/prose update</span></span></code></pre></div><h2 id="예시-간단한-prose-파일" tabindex="-1">예시: 간단한 <code>.prose</code> 파일 <a class="header-anchor" href="#예시-간단한-prose-파일" aria-label="Permalink to &quot;예시: 간단한 \`.prose\` 파일&quot;">​</a></h2><div class="language-prose vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">prose</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># Research + synthesis with two agents running in parallel.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>input topic: &quot;What should we research?&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>agent researcher:</span></span>
<span class="line"><span>  model: sonnet</span></span>
<span class="line"><span>  prompt: &quot;You research thoroughly and cite sources.&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>agent writer:</span></span>
<span class="line"><span>  model: opus</span></span>
<span class="line"><span>  prompt: &quot;You write a concise summary.&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>parallel:</span></span>
<span class="line"><span>  findings = session: researcher</span></span>
<span class="line"><span>    prompt: &quot;Research {topic}.&quot;</span></span>
<span class="line"><span>  draft = session: writer</span></span>
<span class="line"><span>    prompt: &quot;Summarize {topic}.&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>session &quot;Merge the findings + draft into a final answer.&quot;</span></span>
<span class="line"><span>context: { findings, draft }</span></span></code></pre></div><h2 id="파일-위치" tabindex="-1">파일 위치 <a class="header-anchor" href="#파일-위치" aria-label="Permalink to &quot;파일 위치&quot;">​</a></h2><p>OpenProse는 워크스페이스의 <code>.prose/</code> 아래에 상태를 유지합니다:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.prose/</span></span>
<span class="line"><span>├── .env</span></span>
<span class="line"><span>├── runs/</span></span>
<span class="line"><span>│   └── {YYYYMMDD}-{HHMMSS}-{random}/</span></span>
<span class="line"><span>│       ├── program.prose</span></span>
<span class="line"><span>│       ├── state.md</span></span>
<span class="line"><span>│       ├── bindings/</span></span>
<span class="line"><span>│       └── agents/</span></span>
<span class="line"><span>└── agents/</span></span></code></pre></div><p>사용자 수준의 영구 에이전트는 다음에 있습니다:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.prose/agents/</span></span></code></pre></div><h2 id="상태-모드" tabindex="-1">상태 모드 <a class="header-anchor" href="#상태-모드" aria-label="Permalink to &quot;상태 모드&quot;">​</a></h2><p>OpenProse는 여러 상태 백엔드를 지원합니다:</p><ul><li><strong>filesystem</strong> (기본값): <code>.prose/runs/...</code></li><li><strong>in-context</strong>: 소규모 프로그램용 일시적</li><li><strong>sqlite</strong> (실험적): <code>sqlite3</code> 바이너리 필요</li><li><strong>postgres</strong> (실험적): <code>psql</code> 및 연결 문자열 필요</li></ul><p>참고:</p><ul><li>sqlite/postgres는 옵트인이며 실험적입니다.</li><li>postgres 자격 증명은 서브에이전트 로그로 흐릅니다. 전용 최소 권한 DB를 사용하십시오.</li></ul><h2 id="원격-프로그램" tabindex="-1">원격 프로그램 <a class="header-anchor" href="#원격-프로그램" aria-label="Permalink to &quot;원격 프로그램&quot;">​</a></h2><p><code>/prose run &lt;handle/slug&gt;</code>는 <code>https://p.prose.md/&lt;handle&gt;/&lt;slug&gt;</code>로 해결됩니다. 직접 URL은 그대로 가져옵니다. 이는 <code>web_fetch</code> 도구(또는 POST용 <code>exec</code>)를 사용합니다.</p><h2 id="openclaw-런타임-매핑" tabindex="-1">OpenClaw 런타임 매핑 <a class="header-anchor" href="#openclaw-런타임-매핑" aria-label="Permalink to &quot;OpenClaw 런타임 매핑&quot;">​</a></h2><p>OpenProse 프로그램은 OpenClaw 프리미티브에 매핑됩니다:</p><table tabindex="0"><thead><tr><th>OpenProse 개념</th><th>OpenClaw 도구</th></tr></thead><tbody><tr><td>Spawn session / Task tool</td><td><code>sessions_spawn</code></td></tr><tr><td>File read/write</td><td><code>read</code> / <code>write</code></td></tr><tr><td>Web fetch</td><td><code>web_fetch</code></td></tr></tbody></table><p>도구 허용 목록이 이러한 도구를 차단하면 OpenProse 프로그램이 실패합니다. <a href="/openclaw-docs-ko/tools/skills-config">스킬 구성</a>을 참조하십시오.</p><h2 id="보안-승인" tabindex="-1">보안 + 승인 <a class="header-anchor" href="#보안-승인" aria-label="Permalink to &quot;보안 + 승인&quot;">​</a></h2><p><code>.prose</code> 파일을 코드처럼 취급하십시오. 실행 전에 검토하십시오. OpenClaw 도구 허용 목록과 승인 게이트를 사용하여 부작용을 제어하십시오.</p><p>결정론적, 승인 게이트 워크플로의 경우 <a href="/openclaw-docs-ko/tools/lobster">Lobster</a>와 비교하십시오.</p>`,36)])])}const g=a(o,[["render",l]]);export{u as __pageData,g as default};
